import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.C69UpXSI.js";const p=JSON.parse('{"title":"Persistent Memory","description":"","frontmatter":{},"headers":[],"relativePath":"en/configuration/memory.md","filePath":"en/configuration/memory.md"}'),i={name:"en/configuration/memory.md"};function n(r,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="persistent-memory" tabindex="-1">Persistent Memory <a class="header-anchor" href="#persistent-memory" aria-label="Permalink to &quot;Persistent Memory&quot;">​</a></h1><p>TurboDev has a built-in <strong>persistent memory</strong> system that lets the AI agent remember your preferences, decisions, and project facts across sessions. No more starting from scratch every time you reopen the terminal — the agent learns and retains context that matters.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li>At startup, TurboDev loads <code>.turbodev/memory.md</code> (a plain Markdown file, gitignored)</li><li>The content is injected into the system prompt under a <code>## Memory</code> heading</li><li>The LLM sees your persisted facts and uses them as context</li><li>When the LLM learns something durable, it calls the <code>save_memory</code> tool automatically</li><li>Memory <strong>survives compaction</strong> because it lives in the system prompt (not conversation history)</li></ol><p>You can also manage memory manually with <code>/memory</code> commands or by editing the file directly.</p><h2 id="the-markdown-format" tabindex="-1">The Markdown Format <a class="header-anchor" href="#the-markdown-format" aria-label="Permalink to &quot;The Markdown Format&quot;">​</a></h2><p><code>.turbodev/memory.md</code> is a plain Markdown file with one section per category:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Project Memory</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## preferences</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> User prefers TypeScript over JavaScript</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Prefers functional style over OOP</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## decisions</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Using OpenRouter as LLM provider</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## architecture</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> React + Ink for TUI, tsup for bundling</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## facts</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Node 22 LTS is installed</span></span></code></pre></div><p>The file is always human-readable and editable. After manual edits, run <code>/memory reload</code> to update the session.</p><h2 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to &quot;Categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><code>preferences</code></td><td>How the user likes things done</td><td>&quot;prefers pnpm over npm&quot;, &quot;likes functional style&quot;</td></tr><tr><td><code>decisions</code></td><td>Project-level choices that persist</td><td>&quot;using PostgreSQL 16&quot;, &quot;deploying to Vercel&quot;</td></tr><tr><td><code>architecture</code></td><td>Structural facts about the codebase</td><td>&quot;React + Ink for TUI&quot;, &quot;tsup for bundling&quot;</td></tr><tr><td><code>facts</code></td><td>General context (default)</td><td>&quot;Node 22 is installed&quot;, &quot;kDrive slows file I/O&quot;</td></tr></tbody></table><h2 id="the-save-memory-tool" tabindex="-1">The <code>save_memory</code> Tool <a class="header-anchor" href="#the-save-memory-tool" aria-label="Permalink to &quot;The \`save_memory\` Tool&quot;">​</a></h2><p>The LLM has a <code>save_memory</code> tool that it calls when it learns something durable:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tool: save_memory({&quot;content&quot;: &quot;User prefers pnpm, never npm&quot;, &quot;category&quot;: &quot;preferences&quot;})</span></span></code></pre></div><p><strong>What the LLM saves</strong>: preferences, decisions, architecture facts, project context — things useful in <em>future</em> sessions.</p><p><strong>What the LLM does NOT save</strong>: transient state (&quot;currently editing file X&quot;), obvious facts, things already in <code>AGENTS.md</code>.</p><p>The tool is always enabled and cannot be disabled per-agent. It writes only to <code>.turbodev/memory.md</code> (gitignored) — it cannot modify other files.</p><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/memory</code></td><td>Show all memory entries grouped by category</td></tr><tr><td><code>/memory show</code></td><td>Same as <code>/memory</code></td></tr><tr><td><code>/memory add &lt;text&gt;</code></td><td>Add an entry to <code>facts</code> (default category)</td></tr><tr><td><code>/memory add &lt;category&gt; &lt;text&gt;</code></td><td>Add an entry to a specific category</td></tr><tr><td><code>/memory clear</code></td><td>Clear all memory (asks for confirmation)</td></tr><tr><td><code>/memory clear &lt;category&gt;</code></td><td>Clear one category (asks for confirmation)</td></tr><tr><td><code>/memory reload</code></td><td>Re-read <code>.turbodev/memory.md</code> from disk</td></tr></tbody></table><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/memory add preferences Use 2-space indentation, never tabs</span></span>
<span class="line"><span>/memory add decisions We deploy to Vercel, not Netlify</span></span>
<span class="line"><span>/memory add The project uses Tailwind CSS v4</span></span>
<span class="line"><span>/memory clear decisions</span></span></code></pre></div><h2 id="manual-editing" tabindex="-1">Manual Editing <a class="header-anchor" href="#manual-editing" aria-label="Permalink to &quot;Manual Editing&quot;">​</a></h2><p>The memory file is plain Markdown — open it in any editor:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># In your editor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .turbodev/memory.md</span></span></code></pre></div><p>After saving, run <code>/memory reload</code> in TurboDev to pick up the changes.</p><h2 id="token-budget" tabindex="-1">Token Budget <a class="header-anchor" href="#token-budget" aria-label="Permalink to &quot;Token Budget&quot;">​</a></h2><p>Memory is injected into the system prompt, which consumes context window tokens. TurboDev shows a warning when memory exceeds ~500 tokens (roughly 2KB of Markdown).</p><p>To reduce memory usage:</p><ul><li><code>/memory clear &lt;category&gt;</code> to remove outdated entries</li><li>Edit <code>.turbodev/memory.md</code> manually and <code>/memory reload</code></li><li><code>/memory clear</code> to wipe everything and start fresh</li></ul><h2 id="compaction-safety" tabindex="-1">Compaction Safety <a class="header-anchor" href="#compaction-safety" aria-label="Permalink to &quot;Compaction Safety&quot;">​</a></h2><p>When a conversation is compacted (<code>/compact</code> or auto-compaction at 85%), the conversation history is summarized but the <strong>system prompt is preserved</strong>. Because memory lives in the system prompt, your persisted facts survive compaction — they are never lost or summarized away.</p><h2 id="agents-md-vs-memory" tabindex="-1">AGENTS.md vs Memory <a class="header-anchor" href="#agents-md-vs-memory" aria-label="Permalink to &quot;AGENTS.md vs Memory&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>AGENTS.md</th><th>Memory (.turbodev/memory.md)</th></tr></thead><tbody><tr><td><strong>Authored by</strong></td><td>User (manual)</td><td>LLM (via <code>save_memory</code>) + User</td></tr><tr><td><strong>Committed to git</strong></td><td>Yes (shared with team)</td><td>No (gitignored, personal)</td></tr><tr><td><strong>Content</strong></td><td>Project spec, setup, conventions</td><td>Learned facts, preferences, decisions</td></tr><tr><td><strong>Scope</strong></td><td>Static, authoritative</td><td>Dynamic, supplementary</td></tr></tbody></table><p>Both coexist in the system prompt. AGENTS.md is the authoritative project spec; memory is supplementary context the AI has learned.</p><h2 id="limitations-v1" tabindex="-1">Limitations (V1) <a class="header-anchor" href="#limitations-v1" aria-label="Permalink to &quot;Limitations (V1)&quot;">​</a></h2><ul><li><strong>Project-level only</strong> — no global cross-project memory (V2)</li><li><strong>No deduplication</strong> — if the LLM saves the same fact twice, clean up manually</li><li><strong>No auto-capture from compaction</strong> — only the <code>save_memory</code> tool and <code>/memory add</code></li><li><strong>~500 token soft cap</strong> — no automatic truncation, just a UI warning</li><li><strong>No per-agent memory</strong> — all agents in a project share the same memory file</li></ul>`,36)])])}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
